mapper.select:
select riw.*, s.real_name,ri.index_name,ipom.push_object_name push_object_name,s3.real_name appr_person_name from report_index_warning riw left join sys_user s on s.user_id =riw.create_user_id left join report_index ri on ri.index_id = riw.warning_index_id left join im_push_object_manage ipom on ipom.manage_id = riw.push_object_id left join sys_user s3 on s3.user_id = riw.appr_person_id where 1=1
and riw.create_user_id = #{loginUserId}
and ri.index_name like concat('%',#{reportIndexWarning.indexName},'%')
and riw.warning_name like concat('%',#{reportIndexWarning.warningName},'%')
and riw.local_city =#{reportIndexWarning.localCity}
and riw.exec_period =#{reportIndexWarning.execPeriod}
order by riw.create_time desc,riw.appr_time asc


select t.* from report_index_warning t
where
    STR_TO_DATE(t.exec_time , '%H:%i') <= #{endTime}
  and STR_TO_DATE(t.exec_time , '%H:%i') > #{startTime}
  and t.exec_state = '0'
  ORDER BY FIELD(t.warning_level,'urgent','ordinary','alarm')

select riw.*, s.real_name,ri.index_name,ipom.push_object_name push_object_name,s3.real_name appr_person_name from report_index_warning riw left join sys_user s on s.user_id =riw.create_user_id left join report_index ri on ri.index_id = riw.warning_index_id left join im_push_object_manage ipom on ipom.manage_id = riw.push_object_id left join sys_user s3 on s3.user_id = riw.appr_person_id where 1=1 and riw.push_other_object_id !='' and riw.push_other_object_id is not null
and riw.create_user_id = #{loginUserId}
and ri.index_name like concat('%',#{reportIndexWarning.indexName},'%')
and riw.local_city =#{reportIndexWarning.localCity}
and riw.exec_period =#{reportIndexWarning.execPeriod}
order by riw.create_time desc,riw.appr_time asc

select riw.* from report_index_warning riw
where 1=1 and riw.appr_state !='0' and riw.warning_id in

    #{warningId}
